    (async function() {
      debugger;
      // 切换时空
      let spacetimeid = $Variable.spacetimeGUID;
      const STTYPE_ID = 4; // 时空GUID
      let runInfo = {
        stType: STTYPE_ID,
        spaceTime: spacetimeid
      };
      let changeRes = await changeSpace(runInfo);
      // =================================================================================
      const CLOUDID = Number(location.href.split("GetFileContent")[1].split("/")[1]);
      const SUCCESS_CODE = 0;
      const IDENTIFIERTYPE_NAME = 2; // 对象的标识类型=使用名称标识
      const FU_OBJECT_TYPE = 21001; // APP对象
      const APP_NAME = $Variable.APP_NAME; // 用的后台AAPP对象的名称
      let FUNC_NAME = "DeleteClassData"; // 调用APP中的函数名称

      // 1. 后台入参
      let classData = [rowData];
      // 2. 执行call
      const param = new StringMap({
        type: FU_OBJECT_TYPE,
        cloudID: CLOUDID
      });

      let areaID = 0;
      if (undefined !== areaID) {
        param._insert("areaID", areaID, "int32");
      }

      let inParams = new StringMap({});
      inParams._insert("classData", JSON.stringify(classData), "string");

      let input = new StringMap({
        identifierType: IDENTIFIERTYPE_NAME,
        name: APP_NAME,
        funcname: FUNC_NAME,
        params: [new Variant(inParams)]
        // params: []
      });

      let res = await Call(param, input);
      if (SUCCESS_CODE !== res.ret) {
        ShowMes('error', `后台服务异常, 删除<班次信息>失败`);
        return;
      }
      let data = res.returndata;
      let errorcode = data.errorcode;
      if (SUCCESS_CODE !== errorcode) {
        ShowMes('error', `删除<班次信息>失败,请检查相关时空是否正常运行`);
        console.log(data.errormsg);
        return;
      }
      ShowMes('success', `删除<班次信息>成功`);
      // 调用主页面变量改变，更新信息
      $Variable.查询班次信息++;
      // 切换时空
      function changeSpace(runInfo) {
        return new Promise((resolve) => {
          SetRunInfo(runInfo, function(res) {
            resolve(res);
          });
        });
      }
      // 展示消息提示弹窗
      function ShowMes(type, message) {
        var options = {
          message: message,
          type: type,
          offset: 20,
          duration: 3000,
          showClose: true
        };
        ShowMessage(options);
      }
    })();
  }
}); }}],hidden:false,m_id:"c8d14ab1-c4e7-4fd6-a27b-6cbca974fcf8"}],totalData:[]})

